-- =============================================================================
-- LANDING TABLE: L_PO_HDR_BC
-- =============================================================================
-- COPY_DATA loads the raw CSV into this table.
-- The load procedure then cherry-picks columns into stg_fbx_po_hdr.
--
-- SETUP (two steps):
--   1. Create the external table (defines the CSV structure)
--   2. Create the landing table as a copy of the external table structure
--
-- IF BICC SCHEMA CHANGES:
--   DROP TABLE L_PO_HDR_BC;
--   DROP TABLE EXT_PO_HDR_BC;
--   Re-run Step 1 with updated column_list, then re-run Step 2.
-- =============================================================================


-- Step 1: Create external table (one-time, defines CSV structure)
-- This is the source of truth for column names and order.
-- UPDATE the file_uri_list to point at an existing extracted CSV before running.
BEGIN
  DBMS_CLOUD.CREATE_EXTERNAL_TABLE(
    table_name      => 'EXT_PO_HDR_BC',
    credential_name => '<OCI_CREDENTIAL_NAME>',
    file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/<OCI_NAMESPACE>/b/<OCI_BUCKET_NAME>/o/po_header_extracted.csv',
    format          => json_object(
                         'type' value 'csv',
                         'skipheaders' value '1'
                       ),
    column_list     => 'ACCEPTANCEDUEDATE VARCHAR2(4000),ACCEPTANCEREQUIREDFLAG VARCHAR2(4000),ACCEPTANCEWITHINDAYS VARCHAR2(4000),ADDITIONALCONTACTEMAILADDRESS VARCHAR2(4000),AGENTID VARCHAR2(4000),AGINGONSETPOINT VARCHAR2(4000),AGINGPERIODDAYS VARCHAR2(4000),ALLOWITEMDESCUPDATEFLAG VARCHAR2(4000),ALLOWMANULPRICEUPDATEORDER VARCHAR2(4000),ALLOWMULTIPLESITESFLAG VARCHAR2(4000),ALLOWRETROPRICING VARCHAR2(4000),AMOUNTLIMIT VARCHAR2(4000),AMOUNTRELEASED VARCHAR2(4000),APPROVEDDATE VARCHAR2(4000),APPROVEDFLAG VARCHAR2(4000),AWARDAPPROVALENABLEDFLAG VARCHAR2(4000),BCCEMAILADDRESS VARCHAR2(4000),BILLTOLOCATIONID VARCHAR2(4000),BILLINGCYCLECLOSINGDATE VARCHAR2(4000),BILLTOBUID VARCHAR2(4000),BLANKETTOTALAMOUNT VARCHAR2(4000),BUDGETCONTROLENABLEDFLAG VARCHAR2(4000),BUYERMANAGEDTRANSPORTFLAG VARCHAR2(4000),BYPASSAPPROVALFLAG VARCHAR2(4000),CARRIERID VARCHAR2(4000),CATADMINAUTHENABLEDFLAG VARCHAR2(4000),CATADMINAUTHORINGACCEPTANCE VARCHAR2(4000),CCEMAILADDRESS VARCHAR2(4000),CHANGEREQUESTEDBY VARCHAR2(4000),CHANGESUMMARY VARCHAR2(4000),CHECKLISTID VARCHAR2(4000),CLOSEDDATE VARCHAR2(4000),COMMENTS VARCHAR2(4000),CONFIRMINGORDERFLAG VARCHAR2(4000),CONSUMPTIONADVICEFREQUENCY VARCHAR2(4000),CONSUMPTIONADVICESUMMARY VARCHAR2(4000),CONTERMSEXISTFLAG VARCHAR2(4000),CPAREFERENCE VARCHAR2(4000),CREATEDBY VARCHAR2(4000),CREATEDLANGUAGE VARCHAR2(4000),CREATIONDATE VARCHAR2(4000),CURRENCYCODE VARCHAR2(4000),CURRENCYCODE1 VARCHAR2(4000),CURRENTVERSIONID VARCHAR2(4000),DEFAULTBUYERID VARCHAR2(4000),DEFAULTCONSIGNMENTLINEFLAG VARCHAR2(4000),DEFAULTPOTRADEORGID VARCHAR2(4000),DEFAULTPROMISEDATE VARCHAR2(4000),DEFAULTRATETYPE VARCHAR2(4000),DEFAULTTAXATIONCOUNTRY VARCHAR2(4000),DOCTYPEID VARCHAR2(4000),DOCUMENTCREATIONMETHOD VARCHAR2(4000),DOCUMENTSTATUS VARCHAR2(4000),EMAILADDRESS VARCHAR2(4000),EMAILATTACHMENTFILENAME VARCHAR2(4000),ENABLEDFLAG VARCHAR2(4000),ENCUMBRANCEREQUIREDFLAG VARCHAR2(4000),ENDDATE VARCHAR2(4000),ENFORCEMINBIDPRICE VARCHAR2(4000),ENFORCEVENDORHOLDFLAG VARCHAR2(4000),FAX VARCHAR2(4000),FIRMDATE VARCHAR2(4000),FIRSTPTYREGID VARCHAR2(4000),FOBLOOKUPCODE VARCHAR2(4000),FREIGHTTERMSLOOKUPCODE VARCHAR2(4000),FROZENFLAG VARCHAR2(4000),FUNDSSTATUS VARCHAR2(4000),GENORDERFORNEGREQSFLAG VARCHAR2(4000),GENERATEORDERSAUTOMATIC VARCHAR2(4000),GROUPREQUISITIONLINES VARCHAR2(4000),GROUPREQUISITIONS VARCHAR2(4000),INTERFACESOURCECODE VARCHAR2(4000),INVENTORYORGANIZATIONID VARCHAR2(4000),INVOICECLOSETOLERANCE VARCHAR2(4000),LANGUAGECODE VARCHAR2(4000),LASTBILLEDDATE VARCHAR2(4000),LASTRELEASEDATE VARCHAR2(4000),LASTUPDATEDATE VARCHAR2(4000),LASTUPDATEDBY VARCHAR2(4000),LINETYPEID VARCHAR2(4000),MANUALRECEIPTNUMTYPE VARCHAR2(4000),MASTERCONTRACTID VARCHAR2(4000),MATCHOPTION VARCHAR2(4000),MAXATTACHMENTSIZE VARCHAR2(4000),MINRELEASEAMOUNT VARCHAR2(4000),MODEOFTRANSPORT VARCHAR2(4000),MODEOFTRANSPORT1 VARCHAR2(4000),NEGAPPROVALENABLEDFLAG VARCHAR2(4000),NOTETOAUTHORIZER VARCHAR2(4000),NOTETORECEIVER VARCHAR2(4000),NOTETOVENDOR VARCHAR2(4000),OBJECTVERSIONNUMBER VARCHAR2(4000),ORCHESTRATIONORDERFLAG VARCHAR2(4000),OVERRIDINGAPPROVERID VARCHAR2(4000),PAYONCODE VARCHAR2(4000),PAYONUSEFLAG VARCHAR2(4000),PCARDID VARCHAR2(4000),PENDINGSIGNATUREFLAG VARCHAR2(4000),POHEADERID VARCHAR2(4000),PRCBUID VARCHAR2(4000),PRICEBREAKLOOKUPCODE VARCHAR2(4000),PRICECHANGEAMOUNT VARCHAR2(4000),PRICEUPDATETOLERANCE VARCHAR2(4000),PROCUREMENTOPTIONSPRCBUID VARCHAR2(4000),RATE VARCHAR2(4000),RATEDATE VARCHAR2(4000),RATETYPE VARCHAR2(4000),RECEIVECLOSECODE VARCHAR2(4000),RECEIVECLOSETOLERANCE VARCHAR2(4000),RECEIVINGFLAG VARCHAR2(4000),REFERENCENUM VARCHAR2(4000),RELEASEMETHOD VARCHAR2(4000),REQBUID VARCHAR2(4000),RETROPRICEAPPLYUPDATESFLAG VARCHAR2(4000),RETROPRICECOMMUPDATESFLAG VARCHAR2(4000),RETROPRICEINITAPPROVALFLAG VARCHAR2(4000),RETROPRICEOPENORDERFLAG VARCHAR2(4000),REVISEDDATE VARCHAR2(4000),REVISIONNUM VARCHAR2(4000),SEGMENT1 VARCHAR2(4000),SERVICELEVEL VARCHAR2(4000),SERVICELEVEL1 VARCHAR2(4000),SHIPTOLOCATIONID VARCHAR2(4000),SHIPPINGCONTROL VARCHAR2(4000),SIGNATUREREQUIREDFLAG VARCHAR2(4000),SKIPELECTRONICCOMMFLAG VARCHAR2(4000),SOLDTOLEID VARCHAR2(4000),SOURCINGPRIORITY VARCHAR2(4000),SOURCINGSUPPELIGIBILITYFLAG VARCHAR2(4000),SPECIALHANDLINGTYPECODE VARCHAR2(4000),STARTDATE VARCHAR2(4000),STYLEID VARCHAR2(4000),STYLEID1 VARCHAR2(4000),SUBMITAPPROVALAUTOMATIC VARCHAR2(4000),SUBMITDATE VARCHAR2(4000),SUPPLIERAUTHORINGACCEPTANCE VARCHAR2(4000),SUPPLIERNOTIFMETHOD VARCHAR2(4000),TAXATTRIBUTEUPDATECODE VARCHAR2(4000),TAXDOCUMENTSUBTYPE VARCHAR2(4000),TERMSID VARCHAR2(4000),TERMSID1 VARCHAR2(4000),THIRDPTYREGID VARCHAR2(4000),TYPELOOKUPCODE VARCHAR2(4000),USENEEDBYDATE VARCHAR2(4000),USESALESORDERNUMBERFLAG VARCHAR2(4000),USESHIPTO VARCHAR2(4000),USESHIPTOFORGROUPREQS VARCHAR2(4000),USESHIPTOFORGROUPREQS1 VARCHAR2(4000),USERDEFINEDRECEIPTNUMCODE VARCHAR2(4000),USERDEFINEDREQNUMCODE VARCHAR2(4000),VENDORCONTACTID VARCHAR2(4000),VENDORID VARCHAR2(4000),VENDORORDERNUM VARCHAR2(4000),VENDORSITEID VARCHAR2(4000)'
  );
END;
/

-- Step 2: Create landing table from external table structure (empty copy)
CREATE TABLE L_PO_HDR_BC AS
SELECT * FROM EXT_PO_HDR_BC WHERE 1=0;
